def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve dict-based dynamic defaults now that every parameter
    has been parsed. Only applies to options whose value still comes
    from :attr:`ParameterSource.DEFAULT`, and only once all other
    option values are known.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for opt_name, mapping in param.default.items():
            source_param = next(
                (p for p in params if opt_name in p.opts), None
            )

            if source_param is None:
                continue

            source_value = ctx.params.get(source_param.name)  # type: ignore[arg-type]

            if str(source_value) in mapping:
                resolved = mapping[str(source_value)]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)  # type: ignore[arg-type]

